import { ArrowUpRight } from "lucide-react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";

export interface ProgressBarItem {
  day: string;
  hours: number;
  height: number;
  fill: string;
  active?: boolean;
  badge?: string;
}

export interface ProgressCardProps {
  title?: string;
  totalHours: string;
  label: string;
  sublabel?: string;
  bars: ProgressBarItem[];
  onExpand?: () => void;
  className?: string;
}

function formatHours(h: number) {
  const hh = Math.floor(h);
  const mm = Math.round((h - hh) * 60);
  return `${hh}h ${mm.toString().padStart(2, "0")}m`;
}

function ProgressCard({
  title = "Progress",
  totalHours,
  label,
  sublabel,
  bars,
  onExpand,
  className,
}: ProgressCardProps) {
  return (
    <Card variant="elevated" className={cn("flex h-full flex-col gap-5 p-5", className)}>
      <CardHeader
        className="p-0"
        action={
          <Button
            variant="icon"
            size="icon"
            aria-label="Expand"
            className="h-9 w-9 shadow-card"
            onClick={onExpand}
          >
            <ArrowUpRight strokeWidth={1.75} />
          </Button>
        }
      >
        <CardTitle>{title}</CardTitle>
      </CardHeader>

      <CardContent className="flex flex-col gap-5 p-0">
        <div className="flex items-end gap-3">
          <span className="text-4xl font-bold text-neutral-900">{totalHours}</span>
          <div className="pb-1">
            <p className="text-sm font-medium leading-tight text-neutral-900">{label}</p>
            {sublabel && (
              <p className="text-xs leading-tight text-neutral-500">{sublabel}</p>
            )}
          </div>
        </div>

        <div className="relative mt-auto flex h-32 items-end justify-between gap-2">
          {bars.map((bar, i) => (
            <div key={`${bar.day}-${i}`} className="group relative flex flex-1 flex-col items-center gap-2">
              {bar.active && bar.badge && (
                <span className="absolute -top-7 whitespace-nowrap rounded-full bg-brand-yellow px-2.5 py-1 text-xs font-semibold text-neutral-900">
                  {bar.badge}
                </span>
              )}
              <span className="absolute -top-7 z-10 hidden whitespace-nowrap rounded-md bg-neutral-900 px-2 py-1 text-[10px] font-semibold text-white group-hover:block">
                {formatHours(bar.hours)}
              </span>
              <div
                className={cn("w-3 animate-bar-rise rounded-full", bar.fill)}
                style={{ height: `${bar.height}px`, animationDelay: `${i * 60}ms` }}
              />
            </div>
          ))}
        </div>

        <div className="flex justify-between px-1">
          {bars.map((bar, i) => (
            <span key={`label-${bar.day}-${i}`} className="flex-1 text-center text-xs font-medium text-neutral-400">
              {bar.day}
            </span>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}

export { ProgressCard };

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const cardVariants = cva("text-card-foreground transition-shadow", {
  variants: {
    variant: {
      default: "rounded-3xl border bg-card shadow-card",
      elevated: "rounded-3xl border bg-card shadow-card hover:shadow-card-md",
      dark: "rounded-3xl border border-white/5 bg-brand-ink text-card-dark-foreground shadow-card-dark",
      glass: "rounded-3xl border border-white/40 bg-white/60 backdrop-blur shadow-card",
    },
  },
  defaultVariants: { variant: "default" },
});

export interface CardProps
  extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof cardVariants> {}

const Card = React.forwardRef<HTMLDivElement, CardProps>(
  ({ className, variant, ...props }, ref) => (
    <div ref={ref} className={cn(cardVariants({ variant }), className)} {...props} />
  ),
);
Card.displayName = "Card";

const CardHeader = React.forwardRef<
  HTMLDivElement,
  React.HTMLAttributes<HTMLDivElement> & { action?: React.ReactNode }
>(({ className, action, children, ...props }, ref) => (
  <div ref={ref} className={cn("flex items-center justify-between p-5 pb-0", className)} {...props}>
    <div className="flex flex-col space-y-1.5">{children}</div>
    {action}
  </div>
));
CardHeader.displayName = "CardHeader";

const CardTitle = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("text-lg font-semibold leading-none tracking-tight", className)} {...props} />
  ),
);
CardTitle.displayName = "CardTitle";

const CardDescription = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("text-sm text-muted-foreground", className)} {...props} />
  ),
);
CardDescription.displayName = "CardDescription";

const CardContent = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("p-5 pt-0", className)} {...props} />
  ),
);
CardContent.displayName = "CardContent";

const CardFooter = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => (
    <div ref={ref} className={cn("flex items-center p-5 pt-0", className)} {...props} />
  ),
);
CardFooter.displayName = "CardFooter";

export { Card, CardHeader, CardFooter, CardTitle, CardDescription, CardContent, cardVariants };

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-full text-sm font-medium cursor-pointer transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-40 disabled:cursor-not-allowed [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default: "bg-neutral-900 text-white hover:bg-neutral-700",
        yellow: "bg-primary text-primary-foreground hover:bg-primary/90",
        destructive: "bg-destructive text-destructive-foreground shadow-sm hover:bg-destructive/90",
        outline: "border border-border bg-background text-foreground hover:bg-muted",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80",
        ghost: "text-muted-foreground hover:bg-muted hover:text-foreground",
        link: "text-primary underline-offset-4 hover:underline",
        icon: "border border-border bg-card text-muted-foreground shadow-card hover:bg-muted",
      },
      size: {
        default: "h-10 px-5",
        sm: "h-8 px-3 text-xs",
        lg: "h-12 px-8 text-base",
        icon: "h-11 w-11",
      },
    },
    defaultVariants: { variant: "default", size: "default" },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>, VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return (
      <Comp className={cn(buttonVariants({ variant, size, className }))} ref={ref} {...props} />
    );
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };
